select

from t_withdraw_apply

    is_deleted = 0

        and id = #{id}


        and user_id = #{userId}


        and transaction_number like concat('%', #{transactionNumber}, '%')


        and coinId = #{coinId}


        and status = #{status}


        and amount >= #{amountMin}


        and receiving_address like concat('%', #{receivingAddress}, '%')


        and create_time >= #{createTimeStart}


        and create_time <= #{createTimeEnd}



    order by ${orderBy}


    order by create_time desc


    limit #{pageNo}, #{pageSize}

select count(1)
from t_withdraw_apply

    is_deleted = 0

        and id = #{id}


        and user_id = #{userId}


        and transaction_number like concat('%', #{transactionNumber}, '%')


        and coinId = #{coinId}


        and status = #{status}


        and amount >= #{amountMin}


        and receiving_address like concat('%', #{receivingAddress}, '%')


        and create_time >= #{createTimeStart}


        and create_time <= #{createTimeEnd}

select ifnull(sum(amount), 0)
from t_withdraw_apply

    is_deleted = 0
